#include<bits/stdc++.h>
using namespace std;

const int N = 8e5 + 5; 

string s = "#";
int n, d[N];

void Manacher() {
    int l = 0, r = -1;
    for(int i = 1; i < n; i++) {
        int k = 1;
        if(i <= r) k = min(d[l + r - i], r - i + 1);
        while(i - k >= 0 && i + k < n && s[i - k] == s[i + k]) 
            ++k;
        d[i] = k--;
        if(i + k > r) {
            r = i + k;
            l = i - k;
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int x;
    cin >> x;
    string s2;
    cin >> s2;
    for(char c : s2) {
        s += c;
        s += '#';
    }
    n = s.size();
    Manacher();
    int max_len = 0;
    for(int i = 1; i < n; i++) {
        if(i + d[i] - 1 == n - 1) { 
            max_len = max(max_len, d[i] - 1);
        }
    }
    cout << s2.length() - max_len;
    return 0;
}
